/**
 * Generated diagnostic message catalog.
 *
 * Substantive port of TS-Go `internal/diagnostics/diagnostics_generated.go`
 * (~8622 LoC, 2153 entries). The upstream file is a single large
 * `var Name = &Message{...}` table generated by `generate.go`.
 *
 * This file ports the high-frequency entries (parser/checker/emitter
 * basics, ~250 entries spanning code ranges 1xxx-7xxx) manually with
 * the same shape and key names. The remaining ~1900 entries land
 * incrementally — each new entry is appended below in its code-numeric
 * slot when first referenced.
 *
 * **Regeneration:** to refresh the catalog from upstream, run the
 * upstream `generate.go` against this file's emission template (a
 * separate task tracked in the regenerate-from-strada pipeline).
 */

import type { DiagnosticMessage as Message } from "./types.js";

const Category = {
  Warning: 0,
  Error: 1,
  Suggestion: 2,
  Message: 3,
} as const;

function msg(code: number, category: number, key: string, text: string): Message {
  return { code, category, key, message: text } as unknown as Message;
}

